arguments.file_text:
@using sv_cfe803b5e27f4e949b913dd692134621.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="() => OnSelected.InvokeAsync(Channel.Id)">
    <div class="channel-name">
        <span># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@Channel.Description</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }
}

.channel-item {
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 1px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: #2c2d30;
}

.channel-item.active {
    background-color: #1164a3;
    color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-description {
    font-size: 0.8rem;
    color: #9ea0a5;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 1px;
}

.channel-item.active .channel-description {
    color: #c5d0dc;
}

.unread-badge {
    background-color: #e01e5a;
    color: #fff;
    border-radius: 10px;
    padding: 1px 7px;
