arguments.file_text:
@using sv_cfe803b5e27f4e949b913dd692134621.Services
@using sv_cfe803b5e27f4e949b913dd692134621.Helpers

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="HideAll">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@TimeFormatter.FormatRelative(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge"
                        title="@string.Join(", ", reaction.Users)"
                        @onclick="() => OnReactionAdded.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">💬 Reply</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker">😀 React</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
