    position: relative;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #222529;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #e8e8e8;
}

.message-time {
    font-size: 0.75rem;
    color: #8a8d91;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.5;
    color: #d1d2d3;
    word-wrap: break-word;
}

.message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background-color: #2c2d30;
    border: 1px solid #3a3d42;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #d1d2d3;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #3a3d42;
    border-color: #5a5d62;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    background: none;
    border: none;
    color: #1d9bd1;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -4px;
    right: 16px;
    display: flex;
    gap: 2px;
    background-color: #1a1d21;
    border: 1px solid #3a3d42;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.action-btn {
    background: none;
    border: none;
    color: #b5b7bb;
    font-size: 0.8rem;
    padding: 4px 8px;
    border-radius: 4px;
    cursor: pointer;
    white-space: nowrap;
}

.action-btn:hover {
    background-color: #2c2d30;
    color: #e8e8e8;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background-color: #1a1d21;
    border: 1px solid #3a3d42;
    border-radius: 8px;
    padding: 6px;
    margin-top: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    width: fit-content;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.emoji-btn:hover {
    background-color: #2c2d30;
}

