arguments.file_text:
@using sv_cfe803b5e27f4e949b913dd692134621.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    width: 260px;
    min-width: 260px;
    background-color: #19171d;
    border-right: 1px solid #3a3d42;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #3a3d42;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #e8e8e8;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.channel-list::-webkit-scrollbar {
    width: 6px;
}

.channel-list::-webkit-scrollbar-thumb {
    background-color: #3a3d42;
    border-radius: 3px;
}

@using sv_cfe803b5e27f4e949b913dd692134621.Services

<div class="message-list">
    @if (HasMoreMessages)
    {
        <div class="load-more">
            <button class="btn-load-more" @onclick="LoadMore" disabled="@loading">
                @(loading ? "Loading…" : "↑ Load older messages")
            </button>
        </div>
    }

    @foreach (var message in Messages)
    {
        var replyCount = ThreadSummaries?.FirstOrDefault(t => t.RootMessageId == message.Id)?.ReplyCount ?? 0;
        <MessageItem Message="message"
                     ReplyCount="replyCount"
                     OnReplyClicked="OnReplyClicked"
                     OnReactionAdded="OnReactionAdded" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary>? ThreadSummaries { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool loading;

    private async Task LoadMore()
    {
        loading = true;
        await OnLoadMore.InvokeAsync();
        loading = false;
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.message-list::-webkit-scrollbar {
    width: 6px;
}

.message-list::-webkit-scrollbar-thumb {
    background-color: #3a3d42;
    border-radius: 3px;
}

.load-more {
    text-align: center;
    padding: 8px;
}

.btn-load-more {
    background: none;
    border: 1px solid #3a3d42;
    color: #1d9bd1;
    padding: 6px 16px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.85rem;
    transition: background-color 0.15s;
}

.btn-load-more:hover:not(:disabled) {
    background-color: #2c2d30;
}

.btn-load-more:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_cfe803b5e27f4e949b913dd692134621.Services

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>

        <MessageList Messages="Messages"
                     ThreadSummaries="ThreadSummaries"
                     HasMoreMessages="HasMoreMessages"
                     OnLoadMore="OnLoadMore"
                     OnReplyClicked="OnReplyClicked"
                     OnReactionAdded="OnReactionAdded" />

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonText="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary>? ThreadSummaries { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
}

.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background-color: #1a1d21;
    min-width: 0;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #3a3d42;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #e8e8e8;
}

.area-header p {
    margin: 2px 0 0;
    font-size: 0.8rem;
    color: #9ea0a5;
}

.no-channel {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #7a7c80;
    font-size: 1rem;
}

@using sv_cfe803b5e27f4e949b913dd692134621.Services
@using sv_cfe803b5e27f4e949b913dd692134621.Helpers

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="btn-close-thread" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="message-header">
                <span class="message-author">@RootMessage.Author</span>
                <span class="message-time">@TimeFormatter.FormatRelative(RootMessage.SentAt)</span>
            </div>
            <div class="message-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@TimeFormatter.FormatRelative(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonText="Reply"
                      OnSubmit="OnReplySent" />
    }
</div>

