    overflow-y: auto;
    padding: 8px 0;
}

.message-list::-webkit-scrollbar {
    width: 6px;
}

.message-list::-webkit-scrollbar-thumb {
    background-color: #3a3d42;
    border-radius: 3px;
}

.load-more {
    text-align: center;
    padding: 8px;
}

.btn-load-more {
    background: none;
    border: 1px solid #3a3d42;
    color: #1d9bd1;
    padding: 6px 16px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.85rem;
    transition: background-color 0.15s;
}

.btn-load-more:hover:not(:disabled) {
    background-color: #2c2d30;
}

.btn-load-more:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_cfe803b5e27f4e949b913dd692134621.Services

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>

        <MessageList Messages="Messages"
                     ThreadSummaries="ThreadSummaries"
                     HasMoreMessages="HasMoreMessages"
                     OnLoadMore="OnLoadMore"
                     OnReplyClicked="OnReplyClicked"
                     OnReactionAdded="OnReactionAdded" />

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonText="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary>? ThreadSummaries { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
}

.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background-color: #1a1d21;
    min-width: 0;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #3a3d42;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #e8e8e8;
}

.area-header p {
    margin: 2px 0 0;
    font-size: 0.8rem;
    color: #9ea0a5;
}

.no-channel {
    flex: 1;
