    align-items: center;
    justify-content: center;
    color: #7a7c80;
    font-size: 1rem;
}

@using sv_cfe803b5e27f4e949b913dd692134621.Services
@using sv_cfe803b5e27f4e949b913dd692134621.Helpers

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="btn-close-thread" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="message-header">
                <span class="message-author">@RootMessage.Author</span>
                <span class="message-time">@TimeFormatter.FormatRelative(RootMessage.SentAt)</span>
            </div>
            <div class="message-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@TimeFormatter.FormatRelative(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonText="Reply"
                      OnSubmit="OnReplySent" />
    }
</div>

@code {
