toolArgs.file_text:
@using sv_cfe803b5e27f4e949b913dd692134621.Services
@using sv_cfe803b5e27f4e949b913dd692134621.Helpers

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="btn-close-thread" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="message-header">
                <span class="message-author">@RootMessage.Author</span>
                <span class="message-time">@TimeFormatter.FormatRelative(RootMessage.SentAt)</span>
            </div>
            <div class="message-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@TimeFormatter.FormatRelative(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonText="Reply"
                      OnSubmit="OnReplySent" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReplySent { get; set; }
}

.thread-panel {
    width: 340px;
    min-width: 340px;
    background-color: #19171d;
    border-left: 1px solid #3a3d42;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #3a3d42;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
    color: #e8e8e8;
}

.btn-close-thread {
    background: none;
    border: none;
    color: #9ea0a5;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.btn-close-thread:hover {
    background-color: #2c2d30;
    color: #e8e8e8;
}

.thread-root-message {
    padding: 12px 16px;
    border-bottom: 1px solid #3a3d42;
    background-color: #222529;
    flex-shrink: 0;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.8rem;
    color: #9ea0a5;
    border-bottom: 1px solid #3a3d42;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-replies::-webkit-scrollbar {
    width: 6px;
}

.thread-replies::-webkit-scrollbar-thumb {
    background-color: #3a3d42;
    border-radius: 3px;
}

.thread-reply {
    padding: 8px 16px;
}

.thread-reply:hover {
    background-color: #222529;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #e8e8e8;
}

.message-time {
    font-size: 0.75rem;
    color: #8a8d91;
}

.message-content {
    font-size: 0.85rem;
    line-height: 1.4;
    color: #d1d2d3;
    word-wrap: break-word;
}

