@page "/chat"
@layout sv_cfe803b5e27f4e949b913dd692134621.Components.Layout.ChatLayout
@rendermode InteractiveServer
@attribute [StreamRendering]
@using sv_cfe803b5e27f4e949b913dd692134621.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <MessageArea Channel="selectedChannel"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 HasMoreMessages="hasMoreMessages"
                 OnLoadMore="LoadMoreMessages"
                 OnSendMessage="SendMessage"
                 OnReplyClicked="OpenThread"
                 OnReactionAdded="AddReaction" />

    @if (activeThreadRootMessage is not null)
    {
        <ThreadPanel RootMessage="activeThreadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnReplySent="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private int? selectedChannelId;
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private bool hasMoreMessages;
    private int currentSkip;
    private const int PageSize = 50;

    private Message? activeThreadRootMessage;
    private List<Message> threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        currentSkip = 0;
        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMoreMessages = messages.Count >= PageSize;
        threadSummaries = BuildThreadSummaries();
        CloseThread();
        await ChatService.MarkChannelReadAsync(channelId);

        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannelId is null) return;
        currentSkip += PageSize;
        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, currentSkip, PageSize);
        messages.InsertRange(0, older);
        hasMoreMessages = older.Count >= PageSize;
        threadSummaries = BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        activeThreadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (activeThreadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(rootMessageId);
            RefreshThreadSummary(rootMessageId, threadReplies.Count);
        }
    }

    private void CloseThread()
    {
        activeThreadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeThreadRootMessage is null || selectedChannelId is null) return;
        var reply = await ChatService.SendMessageAsync(
            selectedChannelId.Value, content, activeThreadRootMessage.Id);
        threadReplies.Add(reply);
        RefreshThreadSummary(activeThreadRootMessage.Id, threadReplies.Count);
    }

    private async Task AddReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        var msg = messages.FirstOrDefault(m => m.Id == reaction.MessageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == reaction.Emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
            {
                existing.Users.Add("You");
            }
        }
        else
        {
            msg.Reactions.Add(new Reaction(reaction.Emoji, ["You"]));
        }
    }

    private List<ThreadSummary> BuildThreadSummaries()
    {
        return messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }

    private void RefreshThreadSummary(int rootMessageId, int replyCount)
    {
        threadSummaries.RemoveAll(s => s.RootMessageId == rootMessageId);
        if (replyCount > 0)
        {
            threadSummaries.Add(new ThreadSummary(rootMessageId, replyCount, DateTime.UtcNow));
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
    background-color: #1a1d21;
    color: #d1d2d3;
    position: fixed;
    top: 0;
    left: 0;
}

